import hashlib
import time

class Block:
 def __init__(self, index, previous_hash, timestamp, data):
 self.index = index
 self.previous_hash = previous_hash
 self.timestamp = timestamp
 self.data = data
 self.hash = self.calculate_hash()

 def calculate_hash(self):
 data_string = str(self.index) + self.previous_hash + str(self.timestamp) + str(self.data)
 return hashlib.sha256(data_string.encode()).hexdigest()

class Blockchain:
 def __init__(self):
 self.chain = [self.create_genesis_block()]

 def create_genesis_block(self):
 return Block(0, '0', int(time.time()), 'Genesis Block')

 def get_latest_block(self):
 return self.chain[-1]

 def add_block(self, new_block):
 new_block.previous_hash = self.get_latest_block().hash
 new_block.hash = new_block.calculate_hash()
 self.chain.append(new_block)

# Create a new blockchain and add some blocks
blockchain = Blockchain()
blockchain.add_block(Block(1, blockchain.get_latest_block().hash, int(time.time()), 'Transaction 1'))
blockchain.add_block(Block(2, blockchain.get_latest_block().hash, int(time.time()), 'Transaction 2'))

import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;

public class Block {
 private int index;
 private String previousHash;
 private long timestamp;
 private String data;
 private String hash;

 public Block(int index, String previousHash, long timestamp, String data) {
 this.index = index;
 this.previousHash = previousHash;
 this.timestamp = timestamp;
 this.data = data;
 this.hash = calculateHash();
 }

 private String calculateHash() {
 String dataString = index + previousHash + timestamp + data;
 try {
 MessageDigest digest = MessageDigest.getInstance('SHA-256');
 byte[] hashBytes = digest.digest(dataString.getBytes(StandardCharsets.UTF_8));
 return bytesToHex(hashBytes);
 } catch (NoSuchAlgorithmException e) {
 throw new RuntimeException(e);
 }
 }

 private String bytesToHex(byte[] bytes) {
 StringBuilder hexString = new StringBuilder();
 for (byte b : bytes) {
 String hex = Integer.toHexString(0xff & b);
 if (hex.length() == 1) hexString.append('0');
 hexString.append(hex);
 }
 return hexString.toString();
 }
}

public class Blockchain {
 private ArrayList<Block> chain;

 public Blockchain() {
 chain = new ArrayList<>();
 chain.add(createGenesisBlock());
 }

 private Block createGenesisBlock() {
 return new Block(0, '0', System.currentTimeMillis(), 'Genesis Block');
 }

 public Block getLatestBlock() {
 return chain.get(chain.size() - 1);
 }

 public void addBlock(Block newBlock) {
 newBlock.previousHash = getLatestBlock().hash;
 newBlock.hash = newBlock.calculateHash();
 chain.add(newBlock);
 }
}
